module median_filter(  
    input [2:0] min_val,  
    input [2:0] x2,  
    input [2:0] x3,  
    output reg [2:0] median  
);  
always @(*) begin  
    if ((min_val <= x2 && min_val >= x3) || (min_val >= x2 && min_val <= x3))  
        median = min_val;  
    else if ((x2 <= min_val && x2 >= x3) || (x2 >= min_val && x2 <= x3))  
        median = x2;  
    else  
        median = x3;  
end  
endmodule
